#include <iostream>
#include <string>

int main() {
    int t1{}, t2{}, t3{};
    std::cin >> t1 >> t2 >> t3;

    int hot_count{0};

    {
        std::string label{};
        if (t1 >= 90) {
            label = "hot";
            ++hot_count;
        } else if (t1 >= 60) {
            label = "warm";
        } else if (t1 >= 32) {
            label = "cool";
        } else {
            label = "cold";
        }
        std::cout << t1 << ": " << label << "\n";
    }

    {
        std::string label{};
        if (t2 >= 90) {
            label = "hot";
            ++hot_count;
        } else if (t2 >= 60) {
            label = "warm";
        } else if (t2 >= 32) {
            label = "cool";
        } else {
            label = "cold";
        }
        std::cout << t2 << ": " << label << "\n";
    }

    {
        std::string label{};
        if (t3 >= 90) {
            label = "hot";
            ++hot_count;
        } else if (t3 >= 60) {
            label = "warm";
        } else if (t3 >= 32) {
            label = "cool";
        } else {
            label = "cold";
        }
        std::cout << t3 << ": " << label << "\n";
    }

    std::cout << "Hot days: " << hot_count << "\n";
    return 0;
}
